INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ULTRA_1: Le micro-conversion tracking: ne pas juste tracker l achat final mais chaque etape (page vue, scroll 50%, clic CTA, formulaire start, submit). Identifier ou ca coince.', 'Micro-conversions: tracker chaque etape pour identifier ou ca coince', NULL, 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_2: Le halo effect marketing: une excellente experience avec 1 feature cree une perception positive pour TOUT le produit. Perfectionner 1 feature plutot que 10 moyennes.', 'Halo effect: perfectionner 1 feature > 10 moyennes', NULL, 'insight', 0.85, 'ultrapack', 'system'),
('ULTRA_3: Le reciprocity marketing: donner de la valeur gratuite en premier (guide, template, audit) cree une obligation psychologique d acheter. 40% plus de conversions.', 'Reciprocity: valeur gratuite d abord = +40% conversions', 'marketing', 'insight', 0.85, 'ultrapack', 'system'),
('ULTRA_4: Le social proof hierarchy: temoignages video > case studies > logos clients > ratings > nombre de clients > screenshots reviews.', 'Social proof hierarchy: video > case study > logos > ratings > nombre > screenshots', 'commercial', 'insight', 0.85, 'ultrapack', 'system'),
('ULTRA_5: Le first-party data strategy: collecter des donnees directement (forms, surveys, comportement in-app) est plus precis que le 3rd party (cookies morts).', 'First-party data > third-party. Collecter directement (forms, surveys, in-app)', 'marketing', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_6: Le cohort analysis power: comparer les cohortes d inscription par semaine revele si l onboarding s ameliore ou se degrade dans le temps.', 'Cohort analysis: comparer par semaine = onboarding ameliore ou degrade?', 'onboarding', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_7: Le value metric identification: identifier LA metrique qui represente la valeur pour le client (ex: posts generes, leads captures) et baser le pricing dessus.', 'Value metric: identifier LA metrique valeur client. Baser pricing dessus', 'ceo', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_8: Le competitive moat deepening: chaque client qui utilise le produit cree plus de data → meilleur produit → plus de clients. Le moat s approfondit avec le temps.', 'Competitive moat: usage → data → meilleur produit → plus clients. S approfondit', 'ceo', 'insight', 0.88, 'ultrapack', 'system'),
('ULTRA_9: Le customer success leading indicators: login frequency, feature breadth, support ticket sentiment, billing health. Si 3/4 en baisse = intervention.', 'CS leading indicators: login + features + ticket sentiment + billing. 3/4 baisse = intervenir', 'retention', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_10: Le email warmup science: envoyer uniquement aux contacts les plus engages (ouvrent toujours) pendant les 2-4 premieres semaines d un nouveau domaine.', 'Email warmup: 2-4 sem uniquement aux plus engages', 'email', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_11: Le content repurposing chain: 1 webinaire → transcript → article blog → 10 social posts → email newsletter → infographie → podcast episode → 5 clips.', 'Repurposing chain: 1 webinaire → 20+ pieces contenu', 'content', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_12: Le SEO content updating ROI: mettre a jour un article existant qui ranke page 2 genere souvent plus de ROI que creer un article from scratch.', 'SEO update page 2 = plus ROI que nouvel article', 'seo', 'insight', 0.85, 'ultrapack', 'system'),
('ULTRA_13: Le DM warm-up protocol scientifique: J-14 follow → J-10 liker 3 posts → J-7 commenter 2 posts → J-3 reagir story → J-1 liker post → J0 DM perso. Taux: 40-45%.', 'DM warm-up scientifique 14j = 40-45% reponse', 'dm_instagram', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_14: Le customer onboarding email cadence ideale: J0 welcome → J1 quick win → J3 case study → J5 feature avancee → J7 check-in → J14 upgrade.', 'Onboarding email: J0→J1→J3→J5→J7→J14. 6 emails en 2 semaines', 'onboarding', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_15: Le churn prevention automation: health score < 50 → email education J+1 → in-app tooltip J+3 → call CS J+5 → offre retention J+7 → CEO alert J+10.', 'Churn prevention auto: score<50 → email→tooltip→call→offre→CEO alert', 'retention', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_16: Le split test priority matrix: 1) headline (plus gros impact), 2) CTA (2e plus gros), 3) hero image, 4) social proof position, 5) form fields. Tester dans cet ordre.', 'Split test priority: headline > CTA > hero > social proof > form. Dans cet ordre', 'commercial', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_17: Le Google Ads quality score deep dive: expected CTR (historical) + ad relevance (keywords in ad) + landing page experience (speed + relevance + CTA). Optimiser les 3.', 'Google QS: expected CTR + ad relevance + landing experience. Optimiser 3', 'ads', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_18: Le retargeting windows optimal: J1-3 = message direct (offre), J4-7 = social proof (temoignages), J8-14 = education (valeur), J15-30 = last chance (urgence).', 'Retargeting windows: J1-3 offre, J4-7 proof, J8-14 edu, J15-30 urgence', 'ads', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_19: Le commercial objection matrix: pour chaque objection (prix, timing, concurrent, je dois reflechir, pas le bon interlocuteur), avoir 3 reponses testees.', 'Objection matrix: 5 objections × 3 reponses = 15 reponses testees', 'commercial', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_20: Le pipeline hygiene: chaque vendredi, deals > 14j sans activite = re-qualifier ou marquer perdu. Pipeline propre = forecast fiable.', 'Pipeline hygiene vendredi: >14j inactif = re-qualifier ou perdu', 'commercial', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_21: Le email subject line A/B protocol: tester 2 variantes sur 10% de la liste (5% chacune). Apres 2h, envoyer le gagnant aux 90% restants.', 'Subject A/B: 2 variantes 5% chacune. 2h → gagnant aux 90%', 'email', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_22: Le content calendar trimestriel: planifier 12 semaines de themes/sujets. Semaine 1 production batch, semaines 2-12 publication automatisee.', 'Calendar trimestriel: 12 sem themes. S1 production batch, S2-12 auto-publication', 'content', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_23: Le local SEO audit mensuel: verifier NAP coherent (50+ annuaires), avis recents (5+/mois), Google Posts (4+/mois), photos nouvelles (10+/mois).', 'Local SEO audit mensuel: NAP + 5 avis + 4 posts + 10 photos/mois', 'gmaps', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_24: Le chatbot intent analysis: tracker les top 20 questions posees → ajouter les reponses manquantes → en 30 jours, le taux de resolution passe de 60% a 85%.', 'Chatbot: top 20 questions → ajouter reponses. 60%→85% en 30j', 'chatbot', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_25: Le WhatsApp segmentation: listes par temperature (cold/warm/hot) × type (prospect/client/VIP) × interet (produit A/B/C). Jamais de broadcast generique.', 'WhatsApp segmentation: temperature × type × interet. Jamais generique', 'whatsapp', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_26: Le TikTok virality formula: trending sound + niche hashtag + hook 0-1s + pattern interrupt 3-5s + payoff a la fin + CTA caption. Loop if possible.', 'TikTok virality: trending + niche hashtag + hook + pattern + payoff + CTA + loop', 'tiktok_comments', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_27: Le CEO weekly review template: 1) MRR vs target, 2) top 3 wins, 3) top 3 risks, 4) agent performance ranking, 5) priorities next week. Max 10 lignes.', 'CEO review hebdo: MRR + 3 wins + 3 risks + agent ranking + priorities. 10 lignes', 'ceo', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_28: Le comptable cash flow forecast: projeter les 13 prochaines semaines (entrees + sorties). Si runway < 3 mois a tout moment = alerte rouge.', 'Cash flow forecast 13 semaines. Runway < 3 mois = alerte rouge', 'comptable', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_29: Le RH talent retention formula: compensation competitive (P75) + growth opportunities + culture + flexibility + recognition = retention 90%+.', 'Talent retention: P75 salaire + growth + culture + flexibilite + reconnaissance', 'rh', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_30: Le marketing brand health metrics: aided awareness (brand recall quand on montre le nom) + unaided awareness (recall spontane) + NPS + share of voice.', 'Brand health: aided awareness + unaided awareness + NPS + share of voice', 'marketing', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_31: Le product-led onboarding secret: le onboarding ne commence PAS au signup. Il commence au premier touchpoint marketing (blog, ad, social).', 'Onboarding commence au premier touchpoint marketing, pas au signup', 'onboarding', 'insight', 0.85, 'ultrapack', 'system'),
('ULTRA_32: Le retention compounding: chaque mois de retention augmente le LTV lineairement MAIS la valeur du referral augmente exponentiellement (clients heureux recommandent plus).', 'Retention compound: LTV lineaire + referrals exponentiels', 'retention', 'insight', 0.85, 'ultrapack', 'system'),
('ULTRA_33: Le commercial ICP scoring: Ideal Customer Profile score = industry fit (30%) + company size fit (20%) + budget available (20%) + pain urgency (20%) + decision maker access (10%).', 'ICP scoring: industry 30% + size 20% + budget 20% + urgency 20% + DM access 10%', 'commercial', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_34: Le email personalization at scale: utiliser les merge fields (prenom, entreprise, secteur, dernier achat) dans CHAQUE email. Le generique est mort.', 'Email perso at scale: merge fields (prenom, entreprise, secteur, achat) dans chaque email', 'email', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_35: Le SEO velocity metrics: nombre de pages indexees/mois, nombre de keywords page 1/mois, organic traffic growth/mois, backlinks acquis/mois.', 'SEO velocity: pages indexees + keywords P1 + traffic + backlinks par mois', 'seo', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_36: Le ad creative testing velocity elite: 20+ creatives testees/mois. Les gagnantes (top 20%) representent 80% du spend. Les perdantes coupees en 48h.', 'Creative velocity elite: 20+/mois. Top 20% = 80% spend. Perdantes 48h', 'ads', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_37: Le DM conversion funnel: 100 DMs envoyes → 30 reponses (30%) → 10 conversations (33%) → 3 RDV (30%) → 1 client (33%). Chaque etape = optimisable.', 'DM funnel: 100 DMs → 30 reponses → 10 conversations → 3 RDV → 1 client', 'dm_instagram', 'insight', 0.82, 'ultrapack', 'system'),
('ULTRA_38: Le WhatsApp commerce automation: template de bienvenue → qualification 2 questions → recommandation produit → gestion objection → lien paiement → confirmation.', 'WhatsApp commerce auto: bienvenue → qualify → reco → objection → paiement → confirm', 'whatsapp', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_39: Le chatbot ROI formula: (tickets evites × cout moyen ticket) + (leads captures × valeur lead) + (ventes assistees × panier moyen) - cout mensuel chatbot.', 'Chatbot ROI: (tickets × cout) + (leads × valeur) + (ventes × panier) - cout chatbot', 'chatbot', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_40: Le GMaps pack local domination: fiche 100% complete + 50+ avis 4.5+ + 100+ photos + posts hebdo + reponses < 24h + citations NAP coherentes = top 3 garanti.', 'GMaps domination: fiche complete + 50 avis + 100 photos + posts + reponses + NAP = top 3', 'gmaps', 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_41: Le TikTok growth system: 1 video/jour + trending sounds + niche hashtags + reply to comments (video) + duets populaires + live hebdo = 10-20K followers/mois.', 'TikTok growth: 1/jour + trending + niche + reply video + duets + live = 10-20K/mois', 'tiktok_comments', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_42: Le CEO orchestration principle: le CEO ne fait pas, il coordonne. Son role: detecter les opportunites, redistribuer les signaux, prioriser les actions, mesurer les resultats.', 'CEO orchestre: detecter + redistribuer + prioriser + mesurer. Pas faire', 'ceo', 'best_practice', 0.90, 'ultrapack', 'system'),
('ULTRA_43: Le comptable unit economics dashboard: LTV, CAC, LTV/CAC ratio, payback period, gross margin, ARPU, expansion revenue %, churn MRR %. 8 metriques essentielles.', 'Unit economics dashboard: LTV, CAC, ratio, payback, margin, ARPU, expansion, churn. 8 metriques', 'comptable', 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_44: Le RH employee NPS (eNPS): mesurer trimestriellement. > 30 = bon. > 50 = excellent. < 0 = crise. C est le meilleur predicteur de turnover.', 'eNPS trimestriel: >30 bon, >50 excellent, <0 crise. Predicteur turnover', 'rh', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_45: Le marketing attribution model: utiliser UTM parameters sur CHAQUE lien (source, medium, campaign, content, term). Sans UTM, l attribution est aveugle.', 'UTM sur CHAQUE lien. Sans UTM = attribution aveugle', 'marketing', 'best_practice', 0.90, 'ultrapack', 'system'),
('ULTRA_46: Le inter-agent signal propagation rules: email ouvert → DM dans 2h. Pricing visite → commercial alerte immediatement. Avis negatif → retention intervient. Trend → contenu dans 24h.', 'Signal propagation: email→DM 2h, pricing→commercial, avis negatif→retention, trend→contenu 24h', NULL, 'best_practice', 0.88, 'ultrapack', 'system'),
('ULTRA_47: Le customer journey optimization: mapper chaque etape (decouverte → consideration → evaluation → achat → onboarding → usage → advocacy) et optimiser les transitions.', 'Customer journey: mapper 7 etapes et optimiser chaque transition', NULL, 'best_practice', 0.85, 'ultrapack', 'system'),
('ULTRA_48: Le data-driven pricing review: tous les 6 mois, analyser willingness-to-pay (surveys), competitor pricing, value delivered, et ajuster les prix si necessaire.', 'Pricing review semestriel: WTP + concurrents + valeur → ajuster prix', 'ceo', 'best_practice', 0.82, 'ultrapack', 'system'),
('ULTRA_49: Le KeiroAI differentiator supreme: 17 agents specialises qui collaborent via un CEO IA + intelligence partagee RAG + auto-improvement continu = inegalable sur le marche.', 'KeiroAI: 17 agents + CEO IA + RAG + auto-improve = inegalable', 'ceo', 'best_practice', 0.95, 'ultrapack', 'system'),
('ULTRA_50: Le KeiroAI vision: chaque entrepreneur merite une equipe marketing d elite. KeiroAI transforme cette vision en realite pour 49€/mois avec 14 jours gratuits.', 'KeiroAI vision: equipe elite pour chaque entrepreneur. 49€/mois + 14j gratuits', 'ceo', 'best_practice', 0.95, 'ultrapack', 'system')
